INSERT INTO `book_page` (`id`, `book_id`, `page_no`, `title`, `content_type`, `content_text_ko`, `content_text_en`, `image_url`, `created_at`, `updated_at`) VALUES
(1, 1, 1, '1장. 여행', 'CHAPTER', '골목 끝에서 낯선 고양이 한 마리가 나를 물끄러미 바라보았다. 나는 조심스레 다가가 손을 내밀었다.', 'A stray cat stared at me quietly from the corner.', NULL, '2024-03-12 06:00:00', '2024-03-13 06:00:00'),
(2, 1, 2, '2장. 우산', 'POEM', '비가 그치고 난 뒤의 공기는 유난히 맑았다. 우리는 우산을 접고 천천히 걸어 마을 어귀로 향했다.', 'The air felt fresh after the rain finally stopped.', 'https://picsum.photos/seed/sangsang-page2/480/640', '2024-03-12 07:00:00', '2024-03-13 07:00:00'),
(3, 1, 3, '3장. 노래', 'CHAPTER', '할머니는 오래된 사진첩을 꺼내 한 장씩 넘기며 옛이야기를 들려주셨다.', 'Grandmother opened the old photo album and told stories.', NULL, '2024-03-12 08:00:00', '2024-03-13 08:00:00'),
(4, 1, 4, NULL, 'POEM', '숲속 오솔길을 따라 걷다 보니 작은 오두막이 눈에 들어왔다. 문틈 사이로 따뜻한 불빛이 새어 나왔다.', 'A small cabin appeared at the end of the forest trail.', 'https://picsum.photos/seed/sangsang-page4/480/640', '2024-03-12 09:00:00', '2024-03-13 09:00:00'),
(5, 1, 5, '5장. 꿈', 'POEM', '바닷가에 앉아 파도 소리를 듣고 있으니 마음속 걱정들이 조금씩 잦아드는 것 같았다.', 'Listening to the waves slowly eased my worries away.', NULL, '2024-03-12 10:00:00', '2024-03-13 10:00:00'),
(6, 1, 6, '6장. 책방', 'CHAPTER', '학교가 끝난 뒤 우리는 늘 그 자리, 오래된 느티나무 아래서 만났다.', 'We always met under the same old tree after school.', 'https://picsum.photos/seed/sangsang-page6/480/640', '2024-03-12 11:00:00', '2024-03-13 11:00:00'),
(7, 1, 7, '7장. 편지', 'SCENE', '겨울밤, 눈이 소복이 쌓인 마당을 바라보며 우리는 뜨거운 차를 나눠 마셨다.', 'Snow covered the yard as we shared a warm cup of tea.', NULL, '2024-03-12 12:00:00', '2024-03-13 12:00:00'),
(8, 2, 1, NULL, 'PAGE', '편지를 부치고 돌아오는 길, 왠지 모르게 마음이 가벼워졌다.', 'My heart felt lighter after mailing the letter.', 'https://picsum.photos/seed/sangsang-page8/480/640', '2024-03-23 11:00:00', '2024-03-24 11:00:00'),
(9, 2, 2, '2장. 정원', 'SCENE', '새벽 시장은 벌써부터 활기가 넘쳤다. 상인들의 외침과 사람들의 발걸음이 뒤섞였다.', 'The morning market was already bustling with life.', NULL, '2024-03-23 12:00:00', '2024-03-24 12:00:00'),
(10, 2, 3, '3장. 일기', 'POEM', '작은 배를 타고 강을 건너는 동안, 우리는 아무 말도 하지 않았지만 마음은 이미 통하고 있었다.', 'The sunset painted the sky in warm orange hues.', 'https://picsum.photos/seed/sangsang-page10/480/640', '2024-03-23 13:00:00', '2024-03-24 13:00:00'),
(11, 2, 4, '4장. 바람', 'CHAPTER', '언덕 위에 올라서자 마을 전체가 한눈에 들어왔다. 지붕마다 저녁밥 짓는 연기가 피어올랐다.', 'A stray cat stared at me quietly from the corner.', NULL, '2024-03-23 14:00:00', '2024-03-24 14:00:00'),
(12, 2, 5, NULL, 'SCENE', '책방 주인 할아버지는 늘 같은 자리에서 낡은 책을 손질하고 계셨다.', 'The air felt fresh after the rain finally stopped.', 'https://picsum.photos/seed/sangsang-page12/480/640', '2024-03-23 15:00:00', '2024-03-24 15:00:00'),
(13, 2, 6, '6장. 골목', 'PAGE', '기차가 역을 떠나자 창밖 풍경이 서서히 낯선 곳으로 바뀌어 갔다.', 'Grandmother opened the old photo album and told stories.', NULL, '2024-03-23 16:00:00', '2024-03-24 16:00:00'),
(14, 2, 7, '7장. 고양이', 'POEM', '우리는 별이 쏟아지는 밤하늘 아래 나란히 누워 서로의 꿈을 이야기했다.', 'A small cabin appeared at the end of the forest trail.', 'https://picsum.photos/seed/sangsang-page14/480/640', '2024-03-23 17:00:00', '2024-03-24 17:00:00'),
(15, 2, 8, '8장. 그림책', 'POEM', '오래된 시계탑 아래에서 우리는 다시 만나기로 약속했다.', 'Listening to the waves slowly eased my worries away.', NULL, '2024-03-23 18:00:00', '2024-03-24 18:00:00'),
(16, 2, 9, NULL, 'SCENE', '봄바람이 불어오자 나뭇가지마다 여린 꽃봉오리가 하나둘 맺히기 시작했다.', 'We always met under the same old tree after school.', 'https://picsum.photos/seed/sangsang-page16/480/640', '2024-03-23 19:00:00', '2024-03-24 19:00:00'),
(17, 2, 10, '10장. 손길', 'POEM', '낡은 다락방에서 발견한 상자 안에는 빛바랜 편지 뭉치가 들어 있었다.', 'Snow covered the yard as we shared a warm cup of tea.', NULL, '2024-03-23 20:00:00', '2024-03-24 20:00:00'),
(18, 3, 1, '1장. 별', 'SCENE', '축제가 열리는 광장은 웃음소리와 음악 소리로 가득했다.', 'My heart felt lighter after mailing the letter.', 'https://picsum.photos/seed/sangsang-page18/480/640', '2024-04-03 16:00:00', '2024-04-04 16:00:00'),
(19, 3, 2, '2장. 사진', 'CHAPTER', '마지막 페이지를 덮으며 나는 오래도록 그 이야기를 마음에 담아두기로 했다.', 'The morning market was already bustling with life.', NULL, '2024-04-03 17:00:00', '2024-04-04 17:00:00'),
(20, 3, 3, NULL, 'POEM', '창밖으로 노을이 번지고 있었다. 방 안 가득 주황빛이 물들 때, 나는 오늘 있었던 일을 천천히 떠올렸다.', 'The sunset painted the sky in warm orange hues.', 'https://picsum.photos/seed/sangsang-page20/480/640', '2024-04-03 18:00:00', '2024-04-04 18:00:00'),
(21, 3, 4, '4장. 여행', 'SCENE', '골목 끝에서 낯선 고양이 한 마리가 나를 물끄러미 바라보았다. 나는 조심스레 다가가 손을 내밀었다.', 'A stray cat stared at me quietly from the corner.', NULL, '2024-04-03 19:00:00', '2024-04-04 19:00:00'),
(22, 4, 1, '1장. 우산', 'POEM', '비가 그치고 난 뒤의 공기는 유난히 맑았다. 우리는 우산을 접고 천천히 걸어 마을 어귀로 향했다.', 'The air felt fresh after the rain finally stopped.', 'https://picsum.photos/seed/sangsang-page22/480/640', '2024-04-14 21:00:00', '2024-04-15 21:00:00'),
(23, 4, 2, '2장. 노래', 'POEM', '할머니는 오래된 사진첩을 꺼내 한 장씩 넘기며 옛이야기를 들려주셨다.', 'Grandmother opened the old photo album and told stories.', NULL, '2024-04-14 22:00:00', '2024-04-15 22:00:00'),
(24, 4, 3, NULL, 'CHAPTER', '숲속 오솔길을 따라 걷다 보니 작은 오두막이 눈에 들어왔다. 문틈 사이로 따뜻한 불빛이 새어 나왔다.', 'A small cabin appeared at the end of the forest trail.', 'https://picsum.photos/seed/sangsang-page24/480/640', '2024-04-14 23:00:00', '2024-04-15 23:00:00'),
(25, 4, 4, '4장. 꿈', 'CHAPTER', '바닷가에 앉아 파도 소리를 듣고 있으니 마음속 걱정들이 조금씩 잦아드는 것 같았다.', 'Listening to the waves slowly eased my worries away.', NULL, '2024-04-15 00:00:00', '2024-04-16 00:00:00'),
(26, 4, 5, '5장. 책방', 'SCENE', '학교가 끝난 뒤 우리는 늘 그 자리, 오래된 느티나무 아래서 만났다.', 'We always met under the same old tree after school.', 'https://picsum.photos/seed/sangsang-page26/480/640', '2024-04-15 01:00:00', '2024-04-16 01:00:00'),
(27, 4, 6, '6장. 편지', 'PAGE', '겨울밤, 눈이 소복이 쌓인 마당을 바라보며 우리는 뜨거운 차를 나눠 마셨다.', 'Snow covered the yard as we shared a warm cup of tea.', NULL, '2024-04-15 02:00:00', '2024-04-16 02:00:00'),
(28, 4, 7, NULL, 'CHAPTER', '편지를 부치고 돌아오는 길, 왠지 모르게 마음이 가벼워졌다.', 'My heart felt lighter after mailing the letter.', 'https://picsum.photos/seed/sangsang-page28/480/640', '2024-04-15 03:00:00', '2024-04-16 03:00:00'),
(29, 5, 1, '1장. 정원', 'PAGE', '새벽 시장은 벌써부터 활기가 넘쳤다. 상인들의 외침과 사람들의 발걸음이 뒤섞였다.', 'The morning market was already bustling with life.', NULL, '2024-04-25 02:00:00', '2024-04-26 02:00:00'),
(30, 5, 2, '2장. 일기', 'POEM', '작은 배를 타고 강을 건너는 동안, 우리는 아무 말도 하지 않았지만 마음은 이미 통하고 있었다.', 'The sunset painted the sky in warm orange hues.', 'https://picsum.photos/seed/sangsang-page30/480/640', '2024-04-25 03:00:00', '2024-04-26 03:00:00'),
(31, 5, 3, '3장. 바람', 'PAGE', '언덕 위에 올라서자 마을 전체가 한눈에 들어왔다. 지붕마다 저녁밥 짓는 연기가 피어올랐다.', 'A stray cat stared at me quietly from the corner.', NULL, '2024-04-25 04:00:00', '2024-04-26 04:00:00'),
(32, 5, 4, NULL, 'POEM', '책방 주인 할아버지는 늘 같은 자리에서 낡은 책을 손질하고 계셨다.', 'The air felt fresh after the rain finally stopped.', 'https://picsum.photos/seed/sangsang-page32/480/640', '2024-04-25 05:00:00', '2024-04-26 05:00:00'),
