INSERT INTO `comment` (`id`, `book_id`, `member_id`, `reply_to_id`, `content`, `is_deleted`, `created_at`, `updated_at`) VALUES
(1, 40, 33, NULL, '다음 편이 너무 기대돼요.', 0, '2025-05-19 09:00:00', '2025-05-19 09:00:00'),
(2, 9, 12, NULL, '그림체가 너무 예뻐요 :)', 1, '2024-06-12 23:00:00', '2024-06-13 00:00:00'),
(3, 45, 19, NULL, '주인공 마음이 이해가 가서 계속 읽게 되네요.', 0, '2025-07-13 12:00:00', '2025-07-13 12:00:00'),
(4, 51, 53, NULL, '오랜만에 마음이 따뜻해지는 글이었어요.', 0, '2025-09-17 19:00:00', '2025-09-17 19:00:00'),
(5, 48, 36, NULL, '결말이 너무 좋았습니다!', 0, '2025-08-15 05:00:00', '2025-08-15 05:00:00'),
(6, 35, 63, NULL, '이 작가님 다른 작품도 찾아봐야겠어요.', 0, '2025-03-25 13:00:00', '2025-03-25 13:00:00'),
(7, 31, 25, NULL, '짧지만 여운이 남는 이야기네요.', 0, '2025-02-09 18:00:00', '2025-02-09 18:00:00'),
